import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';
import '../../widgets/top_bar.dart';

// --- Models ---
class CategoryModel {
  final String label;
  final String? iconPath;
  final String? iconSvg;

  CategoryModel({required this.label, this.iconPath, this.iconSvg});
}

class DestinationModel {
  final String id;
  final String name;
  final String imageUrl;
  final double rating;
  final bool hasDiscount;
  final bool isFavorite;

  DestinationModel({
    required this.id,
    required this.name,
    required this.imageUrl,
    required this.rating,
    this.hasDiscount = false,
    this.isFavorite = false,
  });
}

// --- Main Page ---
class DestinationPage extends StatelessWidget {
  const DestinationPage({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFFF6F6F6),
      body: Column(
        children: [
          const TopBar(),
          Expanded(
            child: SingleChildScrollView(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const SizedBox(height: 16),
                  _buildSearchBar(),
                  const SizedBox(height: 24),
                  _buildCategories(),
                  const SizedBox(height: 24),
                  const Padding(
                    padding: EdgeInsets.symmetric(horizontal: 20),
                    child: Divider(color: Colors.black12),
                  ),
                  const SizedBox(height: 20),
                  _buildSection('Discount', _mockDestinations),
                  _buildSection('People’s Favorites', _mockDestinations),
                  _buildSection('Hot Destinations', _mockDestinations),
                  const SizedBox(height: 40),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSearchBar() {
    const textStyle = TextStyle(
      color: Colors.black,
      fontSize: 16,
      fontFamily: 'Cairo',
      fontWeight: FontWeight.w400,
    );

    const hintStyle = TextStyle(
      color: Color(0xFF9E9E9E),
      fontSize: 16,
      fontFamily: 'Cairo',
      fontWeight: FontWeight.w400,
    );

    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 20),
      child: Container(
        height: 40,
        decoration: ShapeDecoration(
          color: Colors.white,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(12),
          ),
          shadows: const [
            BoxShadow(
              color: Color(0x26000000),
              blurRadius: 20,
              offset: Offset(0, 4),
            ),
          ],
        ),
        child: const TextField(
          style: textStyle,
          decoration: InputDecoration(
            hintText: 'Search',
            hintStyle: hintStyle,
            prefixIcon: Icon(Icons.search, color: Color(0xFF9E9E9E), size: 18),
            border: InputBorder.none,
            contentPadding: EdgeInsets.symmetric(vertical: 8),
            isDense: true,
          ),
        ),
      ),
    );
  }

